head.script:
scwin.statusFlag = "";
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.tabNo = 0;
scwin.mhnoFlag = "0";
scwin.exRateCheck = "1";
scwin.v_linkcheck = "";
scwin.v_kcomcd = "";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";
scwin.v_tab = "0";
scwin.hd_kcomcd = "DBEX";
scwin.userId = "";
scwin.mhnoLoadingIdx = 0;

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.v_linkcheck = (scwin.params && scwin.params.linkcheck) ? scwin.params.linkcheck : "0";
    scwin.v_kcomcd = (scwin.params && scwin.params.kcomcd) ? scwin.params.kcomcd : "";
    scwin.v_blno = (scwin.params && scwin.params.blno) ? scwin.params.blno : "";
    scwin.v_mhno = (scwin.params && scwin.params.mhno) ? scwin.params.mhno : "";
    scwin.v_bkno = (scwin.params && scwin.params.bkno) ? scwin.params.bkno : "";
    scwin.userId = $c.ses.getUserId();

    scwin.f_DefaultValue();
    scwin.f_getParametrSetting(scwin.v_linkcheck);
    rd_prttype.setValue("K");
    scwin.f_initSetTab();

    tabs1.setLabel("House No 1");
    tabs2.setLabel("House No 2");
    tabs3.setLabel("House No 3");
    tabs4.setLabel("House No 4");
    tabs5.setLabel("House No 5");

    lc_dateTitle.setValue("LADEN ON BOARD");
};

scwin.f_getParametrSetting = function(gubun) {
    switch (gubun) {
        case "0":
            break;
        case "5":
            scwin.mhnoFlag = "1";
            if (scwin.v_blno == "null" || scwin.v_blno == "") {
                ed_hhblno.setValue("");
                ed_hhblno.setFocus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            ed_hhblno.setValue(scwin.v_blno);
            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow();
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.v_mhno);
            lc_dateTitle.setFocus();
            break;
    }
};

scwin.f_DefaultValue = function() {
    scwin.f_Set("INIT");
    ed_hhblno.setFocus();
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Print2, btn_Print3, btn_Print4, btn_Print5, btn_Print6, btn_Print7, btn_Print8, btn_Print9, btn_Print10]);
            $c.gus.cfEnableObjects([tbl_Search]);
            scwin.statusFlag = "I";
            break;
        case "RETRIEVE":
            $c.gus.cfEnableBtnOnly([btn_Print, btn_Print2, btn_Print3, btn_Print4, btn_Print5, btn_Print6, btn_Print7, btn_Print8, btn_Print9, btn_Print10]);
            $c.gus.cfEnableObjects([tbl_Search]);
            scwin.statusFlag = "";
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Print2, btn_Print3, btn_Print4, btn_Print5, btn_Print6, btn_Print7, btn_Print8, btn_Print9, btn_Print10]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_initSetTab = function() {
    $c.gus.cfViewTab(0);
    scwin.f_selectTabMenu(0);
};

scwin.f_selectTabMenu = function(idx) {
    switch (idx) {
        case 0:
            scwin.v_tab = "0";
            break;
        case 1:
            scwin.v_tab = "1";
            break;
        case 2:
            scwin.v_tab = "2";
            break;
        case 3:
            scwin.v_tab = "3";
            break;
        case 4:
            scwin.v_tab = "4";
            break;
    }
    $c.gus.cfViewTab(idx);
};

scwin.f_Retrieve = async function() {
    if (ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["House No 1"]);
        return;
    }
    lc_dateTitle.setFocus();

    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("mhno", lc_dateTitle.getValue());
    if (lc_hhpaynm.getValue() != "") {
        ds_retrieve.set("mhno2", lc_hhpaynm.getValue());
    }
    if (lc_mhno_3.getValue() != "") {
        ds_retrieve.set("mhno3", lc_mhno_3.getValue());
    }
    if (lc_mhno_4.getValue() != "") {
        ds_retrieve.set("mhno4", lc_mhno_4.getValue());
    }
    if (lc_mhno_5.getValue() != "") {
        ds_retrieve.set("mhno5", lc_mhno_5.getValue());
    }

    await $c.sbm.execute(sbm_retrieve);

    $c.gus.cfEnableObj(ed_hhblno, true);
    $c.gus.cfEnableObj(lc_dateTitle, true);
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([ed_hhblno]);
    ds_hmhno.removeAll();
};

scwin.f_dataSetClear = function() {
    ds_houseblList.removeAll();
};

scwin.f_Save = async function(flag) {
    if (await scwin.f_validate()) {
        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk) {
            let checked = 0;
            for (let i = 0; i < ds_houseblList.getRowCount(); i++) {
                ds_houseblList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                ds_houseblList.setCellData(i, "hhblno", ed_hhblno.getValue());
                ds_houseblList.setCellData(i, "mhno", lc_dateTitle.getValue());
                ds_houseblList.setCellData(i, "hhpaynm", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhpaynm"));
                ds_houseblList.setCellData(i, "hhp1", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp1"));
                ds_houseblList.setCellData(i, "hhp2", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp2"));
                ds_houseblList.setCellData(i, "hhp3", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp3"));
                ds_houseblList.setCellData(i, "hhp4", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp4"));
                ds_houseblList.setCellData(i, "hhp5", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp5"));
                ds_houseblList.setCellData(i, "hhp6", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp6"));
                ds_houseblList.setCellData(i, "hhp7", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp7"));
                ds_houseblList.setRowStatus(i, "C");
                checked++;
            }
            for (let i = 0; i < ds_houseblList2.getRowCount(); i++) {
                ds_houseblList2.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                ds_houseblList2.setCellData(i, "hhblno", ed_hhblno_2.getValue());
                ds_houseblList2.setCellData(i, "mhno", lc_hhpaynm.getValue());
                ds_houseblList2.setCellData(i, "hhpaynm", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhpaynm"));
                ds_houseblList2.setCellData(i, "hhp1", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp1"));
                ds_houseblList2.setCellData(i, "hhp2", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp2"));
                ds_houseblList2.setCellData(i, "hhp3", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp3"));
                ds_houseblList2.setCellData(i, "hhp4", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp4"));
                ds_houseblList2.setCellData(i, "hhp5", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp5"));
                ds_houseblList2.setCellData(i, "hhp6", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp6"));
                ds_houseblList2.setCellData(i, "hhp7", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp7"));
                ds_houseblList2.setRowStatus(i, "C");
                checked++;
            }
            for (let i = 0; i < ds_houseblList3.getRowCount(); i++) {
                ds_houseblList3.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                ds_houseblList3.setCellData(i, "hhblno", ed_hhblno_3.getValue());
                ds_houseblList3.setCellData(i, "mhno", lc_mhno_3.getValue());
                ds_houseblList3.setCellData(i, "hhpaynm", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhpaynm"));
                ds_houseblList3.setCellData(i, "hhp1", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp1"));
                ds_houseblList3.setCellData(i, "hhp3", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp3"));
                ds_houseblList3.setCellData(i, "hhp3", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp3"));
                ds_houseblList3.setCellData(i, "hhp4", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp4"));
                ds_houseblList3.setCellData(i, "hhp5", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp5"));
                ds_houseblList3.setCellData(i, "hhp6", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp6"));
                ds_houseblList3.setCellData(i, "hhp7", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp7"));
                ds_houseblList3.setRowStatus(i, "C");
                checked++;
            }
            for (let i = 0; i < ds_houseblList4.getRowCount(); i++) {
                ds_houseblList4.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                ds_houseblList4.setCellData(i, "hhblno", ed_hhblno_4.getValue());
                ds_houseblList4.setCellData(i, "mhno", lc_mhno_4.getValue());
                ds_houseblList4.setCellData(i, "hhpaynm", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhpaynm"));
                ds_houseblList4.setCellData(i, "hhp1", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp1"));
                ds_houseblList4.setCellData(i, "hhp4", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp4"));
                ds_houseblList4.setCellData(i, "hhp3", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp3"));
                ds_houseblList4.setCellData(i, "hhp4", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp4"));
                ds_houseblList4.setCellData(i, "hhp5", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp5"));
                ds_houseblList4.setCellData(i, "hhp6", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp6"));
                ds_houseblList4.setCellData(i, "hhp7", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp7"));
                ds_houseblList4.setRowStatus(i, "C");
                checked++;
            }
            for (let i = 0; i < ds_houseblList5.getRowCount(); i++) {
                ds_houseblList5.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                ds_houseblList5.setCellData(i, "hhblno", ed_hhblno_5.getValue());
                ds_houseblList5.setCellData(i, "mhno", lc_mhno_5.getValue());
                ds_houseblList5.setCellData(i, "hhpaynm", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhpaynm"));
                ds_houseblList5.setCellData(i, "hhp1", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp1"));
                ds_houseblList5.setCellData(i, "hhp5", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp5"));
                ds_houseblList5.setCellData(i, "hhp3", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp3"));
                ds_houseblList5.setCellData(i, "hhp4", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp4"));
                ds_houseblList5.setCellData(i, "hhp5", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp5"));
                ds_houseblList5.setCellData(i, "hhp6", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp6"));
                ds_houseblList5.setCellData(i, "hhp7", ds_houseblListTemp.getCellData(ds_houseblListTemp.getRowPosition(), "hhp7"));
                ds_houseblList5.setRowStatus(i, "C");
                checked++;
            }

            if (rd_prttype.getValue() == "S") {
                if (ed_hhblno.getValue() != "") {
                    if (ds_houseblList.getCellData(0, "autono") != "SURRENDER") {
                        await $c.win.alert("House No 1의  B/L Type이  SURRENDER 아님으로 B/L 발급을 불허합니다.");
                        return false;
                    }
                }
                if (ed_hhblno_2.getValue() != "") {
                    if (ds_houseblList2.getCellData(0, "autono") != "SURRENDER") {
                        await $c.win.alert("House No 2의  B/L Type이  SURRENDER 아님으로 B/L 발급을 불허합니다.");
                        return false;
                    }
                }
                if (ed_hhblno_3.getValue() != "") {
                    if (ds_houseblList3.getCellData(0, "autono") != "SURRENDER") {
                        await $c.win.alert("House No 3의  B/L Type이  SURRENDER 아님으로 B/L 발급을 불허합니다.");
                        return false;
                    }
                }
                if (ed_hhblno_4.getValue() != "") {
                    if (ds_houseblList4.getCellData(0, "autono") != "SURRENDER") {
                        await $c.win.alert("House No 4의  B/L Type이  SURRENDER 아님으로 B/L 발급을 불허합니다.");
                        return false;
                    }
                }
                if (ed_hhblno_5.getValue() != "") {
                    if (ds_houseblList5.getCellData(0, "autono") != "SURRENDER") {
                        await $c.win.alert("House No 5의  B/L Type이  SURRENDER 아님으로 B/L 발급을 불허합니다.");
                        return false;
                    }
                }
            }

            dma_clntNo.set("hhactcust", ds_houseblList.getCellData(0, "hhactcust"));
            await $c.sbm.execute(sbm_retrieveMgntClnt);
            if (ds_mgntYn.getRowCount() > 0 && ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
                await $c.win.alert("House No 1의  Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
                return false;
            }

            dma_clntNo.set("hhactcust", ds_houseblList2.getCellData(0, "hhactcust"));
            await $c.sbm.execute(sbm_retrieveMgntClnt);
            if (ds_mgntYn.getRowCount() > 0 && ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
                await $c.win.alert("House No 2의  Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
                return false;
            }

            dma_clntNo.set("hhactcust", ds_houseblList3.getCellData(0, "hhactcust"));
            await $c.sbm.execute(sbm_retrieveMgntClnt);
            if (ds_mgntYn.getRowCount() > 0 && ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
                await $c.win.alert("House No 3의  Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
                return false;
            }

            dma_clntNo.set("hhactcust", ds_houseblList4.getCellData(0, "hhactcust"));
            await $c.sbm.execute(sbm_retrieveMgntClnt);
            if (ds_mgntYn.getRowCount() > 0 && ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
                await $c.win.alert("House No 4의  Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
                return false;
            }

            dma_clntNo.set("hhactcust", ds_houseblList5.getCellData(0, "hhactcust"));
            await $c.sbm.execute(sbm_retrieveMgntClnt);
            if (ds_mgntYn.getRowCount() > 0 && ds_mgntYn.getCellData(0, "mgntYn") == "Y") {
                await $c.win.alert("House No 5의  Customer는 관리거래처이므로 B/L 발급을 불허합니다.");
                return false;
            }

            await $c.sbm.execute(sbm_save);

            $c.gus.cfEnableObj(ed_hhblno, true);
            $c.gus.cfEnableObj(lc_dateTitle, true);
            $c.gus.cfEnableObj(ed_hhblno_2, true);
            $c.gus.cfEnableObj(lc_hhpaynm, true);
            $c.gus.cfEnableObj(ed_hhblno_3, true);
            $c.gus.cfEnableObj(lc_mhno_3, true);
            $c.gus.cfEnableObj(ed_hhblno_4, true);
            $c.gus.cfEnableObj(lc_mhno_4, true);
            $c.gus.cfEnableObj(ed_hhblno_5, true);
            $c.gus.cfEnableObj(lc_mhno_5, true);

            await scwin.f_Retrieve();
            scwin.f_Set("SAVE");

            if (flag == 0) {
                scwin.f_Print(0);
            } else if (flag == 1) {
                scwin.f_Print(1);
            }
        }
    }
};

scwin.f_Cancel = function() {
    $c.gus.cfEnableObj(ed_hhblno, true);
    $c.gus.cfEnableObj(lc_dateTitle, true);
    ed_hhblno.setFocus();
    scwin.f_Set("RETRIEVE");
    ds_houseblList.undoAll();
};

scwin.f_validate = async function() {
    if (ed_hhblno.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["House B/L"]);
        ed_hhblno.setFocus();
        return false;
    }
    return true;
};

scwin.f_MhnoLoading = function(idx) {
    let strClntNo = "";
    scwin.mhnoLoadingIdx = idx;
    switch (idx) {
        case 1:
            strClntNo = ed_hhblno.getValue().trim();
            if (strClntNo.length > 0) {
                // TODO: MHNO 콤보 데이터 로딩 - sbm_loadMhno 사용하여 ds_hmhno에 데이터 로드
                // 원본: ds_hmhno.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveSeaHouseMhnoListCombo&param1=" + strClntNo;
                // ds_hmhno.Reset();
            } else {
                ds_hmhno.removeAll();
            }
            break;
        case 2:
            strClntNo = ed_hhblno_2.getValue().trim();
            if (strClntNo.length > 0) {
                // TODO: MHNO 콤보 데이터 로딩 - ds_hmhno_2
            } else {
                ds_hmhno_2.removeAll();
            }
            break;
        case 3:
            strClntNo = ed_hhblno_3.getValue().trim();
            if (strClntNo.length > 0) {
                // TODO: MHNO 콤보 데이터 로딩 - ds_hmhno_3
            } else {
                ds_hmhno_3.removeAll();
            }
            break;
        case 4:
            strClntNo = ed_hhblno_4.getValue().trim();
            if (strClntNo.length > 0) {
                // TODO: MHNO 콤보 데이터 로딩 - ds_hmhno_4
            } else {
                ds_hmhno_4.removeAll();
            }
            break;
        case 5:
            strClntNo = ed_hhblno_5.getValue().trim();
            if (strClntNo.length > 0) {
                // TODO: MHNO 콤보 데이터 로딩 - ds_hmhno_5
            } else {
                ds_hmhno_5.removeAll();
            }
            break;
    }
};

scwin.f_chk5 = function() {
    let chkVal = chb_hhp5.getValue();
    if (chkVal != "" && chkVal != "0") {
        lc_dateTitle.setValue("RECEIVED DATE");
        $c.gus.cfDisableObjects([chb_hhp6]);
    } else {
        lc_dateTitle.setValue("");
        $c.gus.cfEnableObjects([chb_hhp6]);
    }
};

scwin.f_chk6 = function() {
    let chkVal = chb_hhp6.getValue();
    if (chkVal != "" && chkVal != "0") {
        lc_dateTitle.setValue("LADEN ON BOARD");
        $c.gus.cfDisableObjects([chb_hhp5]);
    } else {
        lc_dateTitle.setValue("");
        $c.gus.cfEnableObjects([chb_hhp5]);
    }
};

scwin.f_Print = function(flag) {
    ds_OZ.removeAll();

    ds_OZ.insertRow();
    ds_OZ.setCellData(0, "hhblno", ed_hhblno.getValue());
    ds_OZ.setCellData(0, "mhno", lc_dateTitle.getValue());

    if (ed_hhblno_2.getValue() != "") {
        let r2 = ds_OZ.insertRow();
        ds_OZ.setCellData(r2, "hhblno", ed_hhblno_2.getValue());
        ds_OZ.setCellData(r2, "mhno", lc_hhpaynm.getValue());
    }
    if (ed_hhblno_3.getValue() != "") {
        let r3 = ds_OZ.insertRow();
        ds_OZ.setCellData(r3, "hhblno", ed_hhblno_3.getValue());
        ds_OZ.setCellData(r3, "mhno", lc_mhno_3.getValue());
    }
    if (ed_hhblno_4.getValue() != "") {
        let r4 = ds_OZ.insertRow();
        ds_OZ.setCellData(r4, "hhblno", ed_hhblno_4.getValue());
        ds_OZ.setCellData(r4, "mhno", lc_mhno_4.getValue());
    }
    if (ed_hhblno_5.getValue() != "") {
        let r5 = ds_OZ.insertRow();
        ds_OZ.setCellData(r5, "hhblno", ed_hhblno_5.getValue());
        ds_OZ.setCellData(r5, "mhno", lc_mhno_5.getValue());
    }

    OZStartBatch();

    for (let m = 0; m < ds_OZ.getRowCount(); m++) {
        let odiParam = new ODIParam("se_105_01_03");
        odiParam.add("KCOMCD", scwin.hd_kcomcd);
        odiParam.add("HHBLNO", ds_OZ.getCellData(m, "hhblno"));
        odiParam.add("MHNO", ds_OZ.getCellData(m, "mhno"));
        odiParam.add("ONBOARD", lc_dateTitle.getValue());
        odiParam.add("PAYAT", lc_hhpaynm.getValue());
        let v_bank = "";
        let chkBankVal = chb_bank.getValue();
        if (chkBankVal != "" && chkBankVal != "0") {
            v_bank = "1";
            odiParam.add("RMK", v_bank);
        } else {
            v_bank = "0";
            odiParam.add("RMK", v_bank);
        }
        odiParam.add("USERID", scwin.userId);

        let formParam = new FormParam();
        let viewerParam = new ViewerParam();
        viewerParam.add("viewer.useprogressbar", "false");

        let filename = ds_OZ.getCellData(m, "hhblno");
        switch (rd_prttype.getValue()) {
            case "K":
                filename += "_IMAGE BL";
                break;
            case "C":
                filename += "_CHECK BL";
                break;
            case "S":
                filename += "_SURRENDER BL";
                break;
            case "P":
                filename += "_COPY BL";
                break;
        }
        viewerParam.add("export.filename", filename);
        viewerParam.add("export.format", "pdf");
        viewerParam.add("export.path", "C:\\OZExport");

        if (flag == 0) {
            if (rd_prttype.getValue() == "K") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03a.ozr", odiParam, viewerParam, formParam);
            } else if (rd_prttype.getValue() == "C") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03b.ozr", odiParam, viewerParam, formParam);
            } else if (rd_prttype.getValue() == "S") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03c.ozr", odiParam, viewerParam, formParam);
            } else if (rd_prttype.getValue() == "P") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03d.ozr", odiParam, viewerParam, formParam);
            }
        } else if (flag == 1) {
            if (rd_prttype.getValue() == "K") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03a_1.ozr", odiParam, viewerParam, formParam);
            } else if (rd_prttype.getValue() == "C") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03b_1.ozr", odiParam, viewerParam, formParam);
            } else if (rd_prttype.getValue() == "S") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03c_1.ozr", odiParam, viewerParam, formParam);
            } else if (rd_prttype.getValue() == "P") {
                $c.gus.cfOZPreview("/il/seaout/se_105_01_03d_1.ozr", odiParam, viewerParam, formParam);
            }
        }
    }
    OZExecuteBatch();
};

