scwin.f_grdHeiht = function(size) {
    let vObjGrd;
    if (scwin.v_tab == "0") {
        vObjGrd = gr_houseblList;
    } else if (scwin.v_tab == "1") {
        vObjGrd = gr_houseblList2;
    } else if (scwin.v_tab == "2") {
        vObjGrd = gr_houseblList3;
    } else if (scwin.v_tab == "3") {
        vObjGrd = gr_houseblList4;
    } else if (scwin.v_tab == "4") {
        vObjGrd = gr_houseblList5;
    }
    if (vObjGrd) {
        let strHeight = vObjGrd.getStyle("height");
        let intHeight = parseInt(strHeight.replace("px", ""));
        intHeight = intHeight + size;
        if (intHeight > 0) {
            vObjGrd.setStyle("height", intHeight + "px");
        }
    }
};

