scwin.gr_houseblList_onheaderclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "chk") {
        let allChecked = true;
        for (let i = 0; i < ds_houseblList.getRowCount(); i++) {
            if (ds_houseblList.getCellData(i, "chk") != "T") {
                allChecked = false;
                break;
            }
        }
        let newVal = allChecked ? "F" : "T";
        for (let i = 0; i < ds_houseblList.getRowCount(); i++) {
            ds_houseblList.setCellData(i, "chk", newVal);
        }
    }
};

